import type { ConvertibleUnit, FormatOptions, Unit } from '@dynatrace-sdk/units';
import type { Formatter } from '../../../types/formatter.js';
import type { AxisScaleType } from '../../../types/scales.js';
/**
 * Sparkline's y-axis subcomponent props
 * @public
 */
export interface SparklineYAxisProps {
    /**
     * Maximal value on the y-axis.
     * @defaultValue 'data-max'
     */
    max?: number | 'data-max';
    /**
     * Minimal value on the y-axis.
     * @defaultValue 'data-min'
     */
    min?: number | 'data-min';
    /**
     * The scale of the Y axis values. Is only applied to the bar variant.
     * @defaultValue 'linear'
     * */
    scale?: AxisScaleType;
    /** Sparkline Y tick formatter */
    formatter?: Formatter | FormatOptions<Unit, ConvertibleUnit>;
}
